/*
Generated by Text-to-CAD:
A solid cylinder 10mm in diameter and 30mm tall.
*/
@settings(defaultLengthUnit = mm)

// Parameters
diameter = 10
height = 30

// Sketch base circle on XY
sketch = startSketchOn(XY)
profile = circle(sketch, center = [0, 0], diameter = diameter)

// Extrude to height
cylinder = extrude(profile, length = height)

/*
Generated by Text-to-CAD:
A solid sphere with a radius of 15mm.
*/
@settings(defaultLengthUnit = mm)

// Parameters
radius = 15
diameter = 2 * radius

// Sketch a semicircle profile for the sphere
sketch = startSketchOn(XY)
profile = startProfile(sketch, at = [-radius, 0])
  |> xLine(length = diameter)
  |> arc(angleStart = 0, angleEnd = 180, radius = radius)
  |> close()

// Revolve to create the solid sphere
sphere = revolve(profile, axis = X, angle = 360)

/*
Generated by Text-to-CAD:
A flat disk 50mm in diameter and 5mm thick.
*/
@settings(defaultLengthUnit = mm)

// Parameters
diskDiameter = 50
diskThickness = 5

// Sketch and extrude a flat disk
diskSketch = startSketchOn(XY)
diskProfile = circle(diskSketch, center = [0, 0], diameter = diskDiameter)
disk = extrude(diskProfile, length = diskThickness)

/*
Generated by Text-to-CAD:
A solid cylinder 30mm in diameter and 20mm tall with a coaxial through-hole 10mm in diameter.
*/
@settings(defaultLengthUnit = mm)

// Parameters
outerDiameter = 30
height = 20
holeDiameter = 10

// 2D annulus profile
annulus = startSketchOn(XY)
  |> circle(center = [0, 0], diameter = outerDiameter)
  |> subtract2d(tool = circle(center = [0, 0], diameter = holeDiameter))

// Extrude to make the cylinder with through-hole
part = extrude(annulus, length = height)

/*
Generated by Text-to-CAD:
A hollow rectangular box with outer dimensions 60mm × 50mm × 40mm, wall thickness 3mm on all sides, open on the top face.
*/
@settings(defaultLengthUnit = mm)

// Parameters
outerLength = 60
outerWidth = 50
outerHeight = 40
wallThickness = 3

// Outer box
outerSketch = startSketchOn(XY)
  |> rectangle(center = [0, 0], width = outerLength, height = outerWidth)

outerBox = extrude(outerSketch, length = outerHeight)

// Hollow the box and open the top
shell(outerBox, faces = [END], thickness = wallThickness)
